#include<bits/stdc++.h>
using namespace std;
long long tim[100010],val[100010];
long long lson[100010],rson[100010];
long long build(long long x)
{
    scanf("%lld%lld",&tim[x],&val[x]);
    if(val[x]!=0)
    {
        return x;
    }
    lson[x]=x+1;
    long long p=build(lson[x]);
    rson[x]=p+1;
    return build(rson[x]);
}
long long f[6010][1210];
bool vis[5010][6010];
long long dp(long long x,long long cnt)
{
    if(cnt==0)
    {
        return tim[x]*2;
    }
    if(vis[x][cnt])
    {
        return f[x][cnt]+tim[x]*2;
    }
    f[x][cnt]=1e9;
    vis[x][cnt]=true;
    if(val[x]!=0)
    {
        if(cnt>val[x])
        {
            return f[x][cnt]=1e9;
        }
        f[x][cnt]=cnt*5;
        return cnt*5+tim[x]*2;
    }
    for(long long i=0;i<=cnt;i++)
    {
        f[x][cnt]=min(f[x][cnt],dp(lson[x],i)+dp(rson[x],cnt-i));
    }
    f[x][cnt]=min({f[x][cnt],dp(lson[x],cnt),dp(rson[x],cnt)});
    return f[x][cnt]+tim[x]*2;
}
int main()
{
    long long m;
    scanf("%lld",&m);
    if(m==1)
    {
        printf("0");
        return 0;
    }
    m--;
    long long n=build(1);
    long long l=0,r=1200,best;
    while(l<=r)
    {
        long long mid=(l+r)>>1;
        if(dp(1,mid)<=m)
        {
            best=mid;
            l=mid+1;
        }
        else
        {
            r=mid-1;
        }
    }
    printf("%lld",best);
    return 0;
}
